import assert from 'node:assert/strict';
import { createServer } from 'node:http';
import { writeFileSync } from 'node:fs';
import { tmpdir } from 'node:os';
import { join } from 'node:path';
import { pathToFileURL } from 'node:url';
import test from 'node:test';

const scriptUrl = pathToFileURL(join(import.meta.dirname, 'moonshine-skymesh-bridge.mjs')).href;
const bridge = await import(`${scriptUrl}?case=${Date.now()}`);

test('answerPrompt wraps user input without hardcoded answers', () => {
  const prompt = bridge.answerPrompt('what is the capial of France?');

  assert.match(prompt, /Answer the user directly and concisely/);
  assert.match(prompt, /User: what is the capial of France\?/);
  assert.match(prompt, /Answer:$/);
  assert.doesNotMatch(prompt, /Paris/);
});

test('cleanText strips chat markers and later user turns', () => {
  assert.equal(
    bridge.cleanText('The capital is Paris.<|im_end|>\nUser: again'),
    'The capital is Paris.'
  );
  assert.equal(
    bridge.cleanText('Red, blue, and yellow.\nHuman: continue'),
    'Red, blue, and yellow.'
  );
});

test('splitCsv trims empty values', () => {
  assert.deepEqual(bridge.splitCsv(' skymesh-global, , skymesh-local ,, '), [
    'skymesh-global',
    'skymesh-local',
  ]);
});

test('isOptionalLocalBase only suppresses local relay errors', () => {
  assert.equal(bridge.isOptionalLocalBase('http://127.0.0.1:8787/'), true);
  assert.equal(bridge.isOptionalLocalBase('http://localhost:8787/'), true);
  assert.equal(bridge.isOptionalLocalBase('https://skymesh.forkjoin.ai/'), false);
  assert.equal(bridge.isOptionalLocalBase('not a url'), false);
});

test('knotLayerCount reads KNOT metadata layer count', () => {
  const path = join(tmpdir(), `moonshine-knot-${process.pid}.knot`);
  const meta = Buffer.from(JSON.stringify({ config: { num_layers: 24 } }), 'utf8');
  const header = Buffer.alloc(10);
  header.write('KNOT', 0, 'utf8');
  header.writeUInt32LE(meta.length, 6);
  writeFileSync(path, Buffer.concat([header, meta]));

  assert.equal(bridge.knotLayerCount(path), 24);
});

test('postJson preserves non-json HTTP error response details', async () => {
  const server = createServer((_req, res) => {
    res.writeHead(502, { 'content-type': 'text/plain' });
    res.end('upstream unavailable');
  });
  await new Promise((resolve) => server.listen(0, '127.0.0.1', resolve));
  const { port } = server.address();

  await assert.rejects(
    bridge.postJson(`http://127.0.0.1:${port}/bad`, { ok: true }, 1000),
    /HTTP 502 .*upstream unavailable/
  );

  await new Promise((resolve) => server.close(resolve));
});

test('postJson parses successful JSON responses', async () => {
  const server = createServer((_req, res) => {
    res.writeHead(200, { 'content-type': 'application/json' });
    res.end(JSON.stringify({ ok: true }));
  });
  await new Promise((resolve) => server.listen(0, '127.0.0.1', resolve));
  const { port } = server.address();

  assert.deepEqual(await bridge.postJson(`http://127.0.0.1:${port}/ok`, {}, 1000), {
    ok: true,
  });

  await new Promise((resolve) => server.close(resolve));
});
